Experten-Analyse (gemini-3.1-pro-preview):
Hier ist eine professionelle, robuste und präzise Basis-Architektur für dein TCM515-Emulator-Projekt mit dem ESP32-C6 und dem CC1101. 

Die Konfiguration von EnOcean ERP1 (125kbps, ASK, Manchester) auf dem CC1101 ist anspruchsvoll. Da der ESP32 mit 125 kbps (250 kBaud bei Manchester) bei reinem Asynchron-Modus (Interrupt auf jede Flanke, ca. alle 4µs) überlastet wäre, ist der CC1101 hier so konfiguriert, dass er die **Manchester-Dekodierung in Hardware** übernimmt und im **Packet Mode** arbeitet. GDO0 signalisiert das Ende eines empfangenen (Sub-)Telegrams. GDO2 kann für CCA (Clear Channel Assessment / LBT) konfiguriert werden.

### 1. `platformio.ini`
Konfiguration für das ESP32-C6-Target unter ESP-IDF. Wichtig ist das Routing der Konsole über die native USB-JTAG-Schnittstelle, um den TCM515 ESP3-Stream später korrekt über USB abbilden zu können.

```ini
[env:esp32-c6-mini]
platform = espressif32
board = esp32-c6-devkitc-1
framework = espidf
monitor_speed = 115200
; Zwingt ESP-IDF, printf/stdout über den nativen USB-C Port auszugeben
build_flags = 
    -D CONFIG_ESP_CONSOLE_USB_SERIAL_JTAG=1
    -D ESP32_C6
```

### 2. `cc1101_regs.h`
Enthält die berechneten Registerwerte (26 MHz Quarz) für 868.3 MHz, ASK/OOK, 125 kbps und aktivierte Manchester-Dekodierung.

```c
#ifndef CC1101_REGS_H
#define CC1101_REGS_H

#include <stdint.h>

/* CC1101 Command Strobes */
#define CC1101_SRES      0x30        // Reset chip
#define CC1101_SRX       0x34        // Enable RX
#define CC1101_STX       0x35        // Enable TX
#define CC1101_SIDLE     0x36        // Exit RX / TX, turn off freq synthesizer
#define CC1101_SFRX      0x3A        // Flush the RX FIFO buffer
#define CC1101_SFTX      0x3B        // Flush the TX FIFO buffer

/* CC1101 Status Registers (Burst access) */
#define CC1101_PARTNUM   0x30
#define CC1101_VERSION   0x31
#define CC1101_MARCSTATE 0x35

/* CC1101 Configuration Register Array */
typedef struct {
    uint8_t addr;
    uint8_t val;
} cc1101_cfg_t;

/* 
 * Optimierte Parameter für EnOcean ERP1
 * 868.3 MHz, 125 kbps, ASK/OOK, Manchester aktiviert 
 */
static const cc1101_cfg_t erp1_config[] = {
    {0x00, 0x06}, // IOCFG2: GDO2 - 0x06 = Asserts when sync word has been sent / received
    {0x02, 0x01}, // IOCFG0: GDO0 - 0x01 = Associated with RX FIFO (interrupt on packet rx)
    {0x03, 0x47}, // FIFOTHR: RX FIFO Threshold
    {0x04, 0xA5}, // SYNC1: EnOcean Preamble/Sync (Muss an ERP1 Sync-Word angepasst werden)
    {0x05, 0x5A}, // SYNC0: 
    {0x06, 0x15}, // PKTLEN: Max 21 Bytes for ERP1
    {0x07, 0x04}, // PKTCTRL1: Append status (RSSI, LQI)
    {0x08, 0x00}, // PKTCTRL0: Fixed packet length mode, no CRC (EnOcean uses checksum)
    {0x0D, 0x21}, // FREQ2: 868.3 MHz (26 MHz XOSC)
    {0x0E, 0x65}, // FREQ1: 
    {0x0F, 0x6A}, // FREQ0: 
    {0x10, 0x2B}, // MDMCFG4: RX Filter BW ~540kHz (needed for 125kbps OOK)
    {0x11, 0x22}, // MDMCFG3: Data rate 125 kbps
    {0x12, 0x3A}, // MDMCFG2: ASK/OOK (0x30) + Manchester Enable (0x08) + 16/16 Sync (0x02) = 0x3A
    {0x13, 0x22}, // MDMCFG1: Forward Error Correction disabled
    {0x14, 0xF8}, // MDMCFG0: Channel spacing
    {0x15, 0x47}, // DEVIATN: (Ignored in OOK)
    {0x16, 0x07}, // MCSM2: RX_TIME
    {0x17, 0x3F}, // MCSM1: CCA mode (Clear Channel Assessment) für LBT (Listen Before Talk)
    {0x18, 0x18}, // MCSM0: Auto-calibrate when going from IDLE to RX/TX
    {0x19, 0x1D}, // FOCCFG: Frequency Offset Compensation
    {0x1A, 0x1C}, // BSCFG: Bit Synchronization Configuration
    {0x1B, 0x00}, // AGCCTRL2: AGC Control (Crucial for OOK)
    {0x1C, 0x00}, // AGCCTRL1: AGC Control
    {0x1D, 0x92}, // AGCCTRL0: AGC Control
    {0x21, 0xB6}, // FREND1: Front End RX
    {0x22, 0x11}, // FREND0: Front End TX (OOK needs PATABLE[0] for '0' and PATABLE[1] for '1')
    {0x23, 0xEA}, // FSCAL3: Frequency Synthesizer Calibration
    {0x24, 0x2A}, // FSCAL2: 
    {0x25, 0x00}, // FSCAL1: 
    {0x26, 0x1F}, // FSCAL0: 
};

/* PATABLE for OOK: Index 0 is 'off', Index 1 is 'on' (+10dBm z.B.) */
static const uint8_t patable_ook[] = {0x00, 0xC0}; 

#endif // CC1101_REGS_H
```

### 3. `radio_hal.h`
Abstraktionsschicht für das Hardware-Setup und die SPI-Kommunikation.

```c
#ifndef RADIO_HAL_H
#define RADIO_HAL_H

#include <stdint.h>
#include <stdbool.h>

// --- PIN DEFINITIONS (ESP32-C6) ---
#define PIN_GDO0   2
#define PIN_GDO2   3
#define PIN_LED    8
#define PIN_SWITCH 9
#define PIN_SS     18
#define PIN_SCK    19
#define PIN_MISO   20
#define PIN_MOSI   21

#ifdef __cplusplus
extern "C" {
#endif

void radio_hal_init(void);

// SPI Primitives
void cc1101_strobe(uint8_t cmd);
void cc1101_write_reg(uint8_t addr, uint8_t value);
uint8_t cc1101_read_reg(uint8_t addr);
uint8_t cc1101_read_status(uint8_t addr);

// Data Primitives
void cc1101_write_burst(uint8_t addr, const uint8_t *data, uint8_t len);
void cc1101_read_burst(uint8_t addr, uint8_t *data, uint8_t len);

// Interrupts
void radio_hal_enable_rx_isr(void (*isr_callback)(void*), void* arg);

#ifdef __cplusplus
}
#endif

#endif // RADIO_HAL_H
```

### 4. `radio_hal.c`
Implementierung mit ESP-IDF-Treibern (robuste SPI-Transaktionen und GPIO-Interrupts).

```c
#include "radio_hal.h"
#include "cc1101_regs.h"
#include "driver/spi_master.h"
#include "driver/gpio.h"
#include "esp_log.h"
#include "freertos/FreeRTOS.h"
#include "freertos/task.h"
#include "esp_rom_gpio.h"

static const char *TAG = "RADIO_HAL";
static spi_device_handle_t spi_handle;

static void spi_init(void) {
    spi_bus_config_t buscfg = {
        .miso_io_num = PIN_MISO,
        .mosi_io_num = PIN_MOSI,
        .sclk_io_num = PIN_SCK,
        .quadwp_io_num = -1,
        .quadhd_io_num = -1,
        .max_transfer_sz = 64
    };

    spi_device_interface_config_t devcfg = {
        .clock_speed_hz = 5000000, // 5 MHz (CC1101 max is 10 MHz)
        .mode = 0,                 // SPI mode 0
        .spics_io_num = PIN_SS,
        .queue_size = 3,
        .flags = 0
    };

    ESP_ERROR_CHECK(spi_bus_initialize(SPI2_HOST, &buscfg, SPI_DMA_DISABLED));
    ESP_ERROR_CHECK(spi_bus_add_device(SPI2_HOST, &devcfg, &spi_handle));
}

static void gpio_init(void) {
    // LED (Low Active)
    gpio_config_t io_out = {
        .pin_bit_mask = (1ULL << PIN_LED),
        .mode = GPIO_MODE_OUTPUT,
        .pull_up_en = 1,
        .pull_down_en = 0,
        .intr_type = GPIO_INTR_DISABLE
    };
    gpio_config(&io_out);
    gpio_set_level(PIN_LED, 1); // Turn off

    // GDO0, GDO2, Switch
    gpio_config_t io_in = {
        .pin_bit_mask = (1ULL << PIN_GDO0) | (1ULL << PIN_GDO2) | (1ULL << PIN_SWITCH),
        .mode = GPIO_MODE_INPUT,
        .pull_up_en = 1,
        .pull_down_en = 0,
        .intr_type = GPIO_INTR_DISABLE // Enabled later for GDO0
    };
    gpio_config(&io_in);
}

void cc1101_strobe(uint8_t cmd) {
    spi_transaction_t t = {
        .length = 8,
        .tx_data = {cmd},
        .flags = SPI_TRANS_USE_TXDATA
    };
    spi_device_polling_transmit(spi_handle, &t);
}

void cc1101_write_reg(uint8_t addr, uint8_t value) {
    uint8_t tx_data[2] = { addr, value };
    spi_transaction_t t = {
        .length = 16,
        .tx_buffer = tx_data
    };
    spi_device_polling_transmit(spi_handle, &t);
}

uint8_t cc1101_read_reg(uint8_t addr) {
    uint8_t tx_data[2] = { (uint8_t)(addr | 0x80), 0x00 };
    uint8_t rx_data[2] = { 0 };
    spi_transaction_t t = {
        .length = 16,
        .tx_buffer = tx_data,
        .rx_buffer = rx_data
    };
    spi_device_polling_transmit(spi_handle, &t);
    return rx_data[1];
}

uint8_t cc1101_read_status(uint8_t addr) {
    uint8_t tx_data[2] = { (uint8_t)(addr | 0xC0), 0x00 }; // Read + Burst bits sets status mode
    uint8_t rx_data[2] = { 0 };
    spi_transaction_t t = {
        .length = 16,
        .tx_buffer = tx_data,
        .rx_buffer = rx_data
    };
    spi_device_polling_transmit(spi_handle, &t);
    return rx_data[1];
}

void cc1101_write_burst(uint8_t addr, const uint8_t *data, uint8_t len) {
    uint8_t header = addr | 0x40; // Write + Burst
    spi_transaction_t t = {
        .length = 8,
        .tx_data = {header},
        .flags = SPI_TRANS_USE_TXDATA
    };
    spi_device_polling_transmit(spi_handle, &t); // Send Address

    spi_transaction_t t_data = {
        .length = len * 8,
        .tx_buffer = data
    };
    spi_device_polling_transmit(spi_handle, &t_data); // Send Data
}

void cc1101_read_burst(uint8_t addr, uint8_t *data, uint8_t len) {
    uint8_t header = addr | 0xC0; // Read + Burst
    spi_transaction_t t = {
        .length = 8,
        .tx_data = {header},
        .flags = SPI_TRANS_USE_TXDATA
    };
    spi_device_polling_transmit(spi_handle, &t); // Send Address

    spi_transaction_t t_data = {
        .length = len * 8,
        .rx_buffer = data
    };
    spi_device_polling_transmit(spi_handle, &t_data); // Read Data
}

void radio_hal_init(void) {
    gpio_init();
    spi_init();

    // Hardware Reset Sequence for CC1101
    cc1101_strobe(CC1101_SRES);
    vTaskDelay(pdMS_TO_TICKS(10));

    // Verify SPI Connection
    uint8_t partnum = cc1101_read_status(CC1101_PARTNUM);
    uint8_t version = cc1101_read_status(CC1101_VERSION);
    ESP_LOGI(TAG, "CC1101 Found - Part: 0x%02X, Version: 0x%02X", partnum, version);

    // Apply ERP1 Configuration
    for (int i = 0; i < sizeof(erp1_config)/sizeof(cc1101_cfg_t); i++) {
        cc1101_write_reg(erp1_config[i].addr, erp1_config[i].val);
    }

    // Write PATABLE for OOK
    cc1101_write_burst(0x3E, patable_ook, 2);

    // Start Receiving
    cc1101_strobe(CC1101_SRX);
    ESP_LOGI(TAG, "CC1101 Initialized and in RX Mode");
}

void radio_hal_enable_rx_isr(void (*isr_callback)(void*), void* arg) {
    gpio_install_isr_service(0);
    // GDO0 triggers on falling edge (packet received & FIFO filled)
    gpio_set_intr_type(PIN_GDO0, GPIO_INTR_NEGEDGE); 
    gpio_isr_handler_add(PIN_GDO0, isr_callback, arg);
}
```

### Besondere Architekturnotizen für deinen Stack:
1. **OOK PATABLE**: Bei ASK/OOK-Modulation liest der CC1101 die Sendeleistung für "0" aus `PATABLE[0]` und für "1" aus `PATABLE[1]`. Ich habe das im Burst-Write am Ende der Initialisierung berücksichtigt.
2. **Interrupt & Subtelegram-Timing**: Die `IOCFG0` steht auf `0x01` (RX FIFO gefüllt/Paket komplett). Wenn du echtes **Subtelegram-Timing (z.B. 10ms Wait-Time nach Spec)** brauchst, wirst du in der Hauptschleife (oder im ESP32-Timer) den Interrupt via `radio_hal_enable_rx_isr` fangen, den Timestamp (ESP-Timer) loggen, das FIFO über `cc1101_read_burst(0x3F, buf, len)` leeren und in die ESP3 UART-Warteschlange legen.
3. **Listen Before Talk (LBT)**: Die `MCSM1` Register sind auf `0x3F` konfiguriert (Clear Channel Assessment). Bevor du via `CC1101_STX` sendest, prüft der Chip automatisch, ob der Kanal frei ist. GDO2 (`IOCFG2 = 0x06`) kann als Trägersignal-Feedback gelesen werden.
4. **EnOcean Sync Word**: Der CC1101 sucht derzeit nach `0xA55A`. Die tatsächliche Manchester-Preamble auf Bit-Ebene bei ERP1 kann abweichen. Falls Pakete gedroppt werden, setze `MDMCFG2` testweise auf `0x38` (No Sync Word / Asynchronous Mode) und leite GDO0 an den ESP32-RMT (Remote Control Peripheral) weiter, um die Hardware-Bit-Sampling-Engine des ESP32 zu nutzen, anstatt die CPU durch Flanken-Interrupts zu belasten.

