        .signal_delay_ticks = 200, // Timeout: 200µs ohne Flanke = Ende des Pakets
    };

    rmt_symbol_word_t raw_symbols[256];

    while (1) {
        // Starte RMT Empfang
        ESP_ERROR_CHECK(rmt_receive(rx_channel, raw_symbols, sizeof(raw_symbols), &receive_config));

        // Warte auf Abschluss (in Prod: verwende Callbacks & Queues)
        rmt_rx_done_event_data_t rx_data;
        // ... (Warte-Logik basierend auf FreeRTOS Event/Queue aus dem RMT Callback)

        // Dekodierungs-Logik auf den raw_symbols
