    uint8_t buffer[64] = {0};
    int bit_idx = 0;
    int byte_idx = 0;

    // State machine für Manchester (Standard: Flanke Mitte des Bits)
    // IEEE 802.3: High->Low = 0, Low->High = 1
    // (EnOcean nutzt oft G.E. Thomas: High->Low = 1, abhängig von Invertierung im CC1101)

    for (int i = 0; i < count; i++) {
        uint32_t duration_0 = symbols[i].duration_0;
        uint32_t duration_1 = symbols[i].duration_1;

        // Verarbeite Level 0 (duration_0) und Level 1 (duration_1)
        // Unterscheide zwischen PULSE_SHORT und PULSE_LONG.
        // Ein langer Puls bedeutet: Aktuelles Bit ist gleich dem vorherigen Bit.
        // Zwei kurze Pulse bedeuten: Aktuelles Bit wechselt (Flanke in der Mitte).

        /* 
           Implementiere hier eine Shift-Register-Logik.
           Suche im Shift-Register nach der Preamble (0xA5 / 0x5A).
